import { useState, useEffect } from 'react'
import { BookmarkIcon, BookmarkSlashIcon, PlusIcon, XMarkIcon } from '@heroicons/react/24/outline'
import { useAuth } from '../context/AuthContext'

// Mock data for saved articles - in production, this would come from an API
const mockSavedArticles = [
  {
    id: 1,
    headline: "Global Markets Rally as Economic Indicators Show Strong Growth",
    subtitle: "Investors celebrate as major indices reach new heights",
    category: "Economics",
    image: "https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?w=800&h=600&fit=crop",
    savedDate: "2024-01-15",
    size: "wide"
  },
  {
    id: 2,
    headline: "Championship Final Set for Next Weekend",
    subtitle: "Top teams prepare for the ultimate showdown",
    category: "Sports",
    image: "https://images.unsplash.com/photo-1574629810360-7efbbe195018?w=800&h=600&fit=crop",
    savedDate: "2024-01-14",
    size: "tall"
  },
  {
    id: 3,
    headline: "New Film Breaks Box Office Records",
    subtitle: "Audiences flock to theaters for latest blockbuster",
    category: "Entertainment",
    image: "https://images.unsplash.com/photo-1489599849927-2ee91cede3ba?w=800&h=600&fit=crop",
    savedDate: "2024-01-13",
    size: "square"
  },
  {
    id: 4,
    headline: "Tech Innovation Transforms Healthcare Industry",
    subtitle: "AI-powered solutions revolutionize patient care",
    category: "Technology",
    image: "https://images.unsplash.com/photo-1559757148-5c350d0d3c56?w=800&h=600&fit=crop",
    savedDate: "2024-01-12",
    size: "regular"
  },
  {
    id: 5,
    headline: "Scientists Discover New Species in Deep Ocean",
    subtitle: "Marine biologists excited about groundbreaking find",
    category: "Science",
    image: "https://images.unsplash.com/photo-1559827260-dc66d52bef19?w=800&h=600&fit=crop",
    savedDate: "2024-01-11",
    size: "large"
  },
  {
    id: 6,
    headline: "Cultural Festival Celebrates Local Heritage",
    subtitle: "Community comes together for annual celebration",
    category: "Culture",
    image: "https://images.unsplash.com/photo-1514525253161-7a46d19cd819?w=800&h=600&fit=crop",
    savedDate: "2024-01-10",
    size: "square"
  },
]

const categoryColors = {
  Sports: "bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-300",
  International: "bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300",
  Economics: "bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300",
  Entertainment: "bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-300",
  Technology: "bg-indigo-100 text-indigo-700 dark:bg-indigo-900/30 dark:text-indigo-300",
  Science: "bg-cyan-100 text-cyan-700 dark:bg-cyan-900/30 dark:text-cyan-300",
  Culture: "bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-300",
  Lifestyle: "bg-pink-100 text-pink-700 dark:bg-pink-900/30 dark:text-pink-300",
  Local: "bg-teal-100 text-teal-700 dark:bg-teal-900/30 dark:text-teal-300"
}

const sizeStyles = {
  wide: "aspect-[21/9]",
  large: "aspect-[16/9]",
  regular: "aspect-[4/3]",
  tall: "aspect-[3/4]",
  square: "aspect-square"
}

export default function ClippingsPage() {
  const { user, isAuthenticated } = useAuth()
  const [savedArticles, setSavedArticles] = useState([])
  const [boards, setBoards] = useState([
    { id: 1, name: 'Tech News', articleIds: [4] },
    { id: 2, name: 'Science & Discovery', articleIds: [5] },
    { id: 3, name: 'Entertainment', articleIds: [3] }
  ])
  const [selectedBoard, setSelectedBoard] = useState(null) // null = "All", or board id
  const [showCreateBoard, setShowCreateBoard] = useState(false)
  const [newBoardName, setNewBoardName] = useState('')
  const [showAddToBoard, setShowAddToBoard] = useState(null) // article id

  useEffect(() => {
    // In production, fetch saved articles from API
    // For now, use mock data regardless of authentication
    setSavedArticles(mockSavedArticles)
  }, [])

  const handleRemoveArticle = (articleId) => {
    setSavedArticles(savedArticles.filter(article => article.id !== articleId))
    // Remove article from all boards
    setBoards(boards.map(board => ({
      ...board,
      articleIds: board.articleIds.filter(id => id !== articleId)
    })))
    // In production, make API call to remove article
  }

  const handleCreateBoard = () => {
    if (newBoardName.trim()) {
      const newBoard = {
        id: Date.now(),
        name: newBoardName.trim(),
        articleIds: []
      }
      setBoards([...boards, newBoard])
      setNewBoardName('')
      setShowCreateBoard(false)
    }
  }

  const handleAddToBoard = (articleId, boardId) => {
    setBoards(boards.map(board => {
      if (board.id === boardId) {
        if (!board.articleIds.includes(articleId)) {
          return { ...board, articleIds: [...board.articleIds, articleId] }
        }
      }
      return board
    }))
    setShowAddToBoard(null)
  }

  const handleRemoveFromBoard = (articleId, boardId) => {
    setBoards(boards.map(board => {
      if (board.id === boardId) {
        return { ...board, articleIds: board.articleIds.filter(id => id !== articleId) }
      }
      return board
    }))
  }

  const handleDeleteBoard = (boardId) => {
    setBoards(boards.filter(board => board.id !== boardId))
    if (selectedBoard === boardId) {
      setSelectedBoard(null)
    }
  }

  // Get articles to display based on selected board
  const getDisplayArticles = () => {
    if (selectedBoard === null) {
      return savedArticles
    }
    const board = boards.find(b => b.id === selectedBoard)
    if (!board) return []
    return savedArticles.filter(article => board.articleIds.includes(article.id))
  }

  const displayArticles = getDisplayArticles()

  const formatDate = (dateString) => {
    const date = new Date(dateString)
    const now = new Date()
    const diffTime = Math.abs(now - date)
    const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24))

    if (diffDays === 0) return 'Saved today'
    if (diffDays === 1) return 'Saved yesterday'
    if (diffDays < 7) return `Saved ${diffDays} days ago`

    return date.toLocaleDateString('en-US', { 
      month: 'short', 
      day: 'numeric',
      year: date.getFullYear() !== now.getFullYear() ? 'numeric' : undefined
    })
  }

  return (
    <div className="isolate bg-cream-50 dark:bg-gray-900 px-8 py-28 sm:py-36 lg:px-10 min-h-screen">
      <div className="mx-auto max-w-7xl">
        {/* Header Section */}
        <div className="mx-auto max-w-3xl text-center mb-8">
          <h1 className="text-balance text-4xl font-serif font-normal tracking-tight text-soft-blue-800 dark:text-gray-100 sm:text-5xl">
            your clippings
          </h1>
          <p className="mt-6 text-sm text-soft-blue-600 dark:text-gray-400">
            organize your saved articles into boards
          </p>
        </div>

        {/* Boards Navigation */}
        <div className="mb-10 flex justify-center overflow-x-auto scrollbar-hide scroll-smooth -mx-4 px-4">
          <div className="flex gap-1 pb-3 min-w-max border-b border-soft-blue-100 dark:border-gray-800">
            <button
              onClick={() => setSelectedBoard(null)}
              className={`relative px-5 py-2.5 text-sm font-medium whitespace-nowrap transition-all duration-300 ease-in-out ${
                selectedBoard === null
                  ? 'text-soft-blue-700 dark:text-soft-blue-400'
                  : 'text-soft-blue-500 dark:text-gray-500 hover:text-soft-blue-700 dark:hover:text-gray-300'
              }`}
            >
              All
              {selectedBoard === null && (
                <span className="absolute bottom-0 left-0 right-0 h-0.5 bg-soft-blue-600 dark:bg-soft-blue-400 rounded-full transition-all duration-300 ease-in-out opacity-100 scale-x-100" />
              )}
            </button>
            {boards.map((board) => (
              <button
                key={board.id}
                onClick={() => setSelectedBoard(board.id)}
                className={`relative px-5 py-2.5 text-sm font-medium whitespace-nowrap transition-all duration-300 ease-in-out ${
                  selectedBoard === board.id
                    ? 'text-soft-blue-700 dark:text-soft-blue-400'
                    : 'text-soft-blue-500 dark:text-gray-500 hover:text-soft-blue-700 dark:hover:text-gray-300'
                }`}
              >
                {board.name}
                {selectedBoard === board.id && (
                  <span className="absolute bottom-0 left-0 right-0 h-0.5 bg-soft-blue-600 dark:bg-soft-blue-400 rounded-full transition-all duration-300 ease-in-out opacity-100 scale-x-100" />
                )}
                {selectedBoard === board.id && (
                  <button
                    onClick={(e) => {
                      e.stopPropagation()
                      if (window.confirm(`Delete board "${board.name}"?`)) {
                        handleDeleteBoard(board.id)
                      }
                    }}
                    className="ml-2 text-red-500 hover:text-red-700 dark:text-red-400 dark:hover:text-red-300"
                    aria-label="Delete board"
                  >
                    <XMarkIcon className="h-4 w-4 inline" />
                  </button>
                )}
              </button>
            ))}
            <button
              onClick={() => setShowCreateBoard(true)}
              className="px-5 py-2.5 text-sm font-medium whitespace-nowrap text-soft-blue-500 dark:text-gray-500 hover:text-soft-blue-700 dark:hover:text-gray-300 transition-all duration-300 ease-in-out flex items-center gap-1"
            >
              <PlusIcon className="h-4 w-4" />
              New Board
            </button>
          </div>
        </div>

        {/* Create Board Modal */}
        {showCreateBoard && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 dark:bg-black/70 backdrop-blur-sm">
            <div className="bg-white dark:bg-gray-800 rounded-2xl p-6 max-w-md w-full mx-4 shadow-xl">
              <h3 className="text-lg font-semibold text-soft-blue-800 dark:text-gray-100 mb-4">
                Create New Board
              </h3>
              <input
                type="text"
                value={newBoardName}
                onChange={(e) => setNewBoardName(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') handleCreateBoard()
                  if (e.key === 'Escape') setShowCreateBoard(false)
                }}
                placeholder="Board name"
                className="w-full px-4 py-2 rounded-xl border border-soft-blue-200 dark:border-gray-700 bg-white dark:bg-gray-800 text-soft-blue-900 dark:text-gray-200 focus:ring-2 focus:ring-soft-blue-500 focus:outline-none"
                autoFocus
              />
              <div className="flex gap-3 mt-6">
                <button
                  onClick={handleCreateBoard}
                  className="flex-1 rounded-full bg-soft-blue-600 dark:bg-soft-blue-500 px-4 py-2 text-sm font-medium text-white hover:bg-soft-blue-700 dark:hover:bg-soft-blue-600 transition-colors"
                >
                  Create
                </button>
                <button
                  onClick={() => {
                    setShowCreateBoard(false)
                    setNewBoardName('')
                  }}
                  className="flex-1 rounded-full bg-white dark:bg-gray-700 px-4 py-2 text-sm font-medium text-soft-blue-700 dark:text-gray-300 border border-soft-blue-200 dark:border-gray-600 hover:bg-soft-blue-50 dark:hover:bg-gray-600 transition-colors"
                >
                  Cancel
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Articles Grid */}
        {savedArticles.length > 0 ? (
          <>
            {displayArticles.length > 0 ? (
              <div className="columns-1 sm:columns-2 lg:columns-4 gap-6 space-y-6">
                {displayArticles.map((article) => {
                  const articleBoards = boards.filter(board => board.articleIds.includes(article.id))
                  return (
                    <div
                      key={article.id}
                      className="break-inside-avoid rounded-2xl border border-soft-blue-200 dark:border-gray-700 bg-white dark:bg-gray-800 overflow-hidden shadow-sm hover:shadow-2xl hover:-translate-y-2 hover:scale-[1.02] transition-all duration-300 group"
                    >
                      {/* IMAGE */}
                      <div className={`relative w-full overflow-hidden ${sizeStyles[article.size] || sizeStyles.regular}`}>
                        <img
                          src={article.image}
                          alt={article.headline}
                          className="w-full h-full object-cover grayscale group-hover:grayscale-0 group-hover:scale-105 transition duration-300"
                        />

                        {/* Gradient overlay */}
                        <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-black/20 to-transparent z-10"></div>

                        {/* Category Badge */}
                        <span
                          className={`absolute top-4 left-4 inline-flex items-center rounded-full px-3 py-1 text-xs font-medium z-20 ${categoryColors[article.category] || "bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300"}`}
                        >
                          {article.category}
                        </span>

                        {/* Action Buttons */}
                        <div className="absolute top-4 right-4 flex items-center gap-2 z-20">
                          {/* Add to Board Button */}
                          <div className="relative">
                            <button
                              onClick={(e) => {
                                e.stopPropagation()
                                setShowAddToBoard(showAddToBoard === article.id ? null : article.id)
                              }}
                              className="p-2 rounded-full bg-white/90 dark:bg-gray-800/90 backdrop-blur-sm hover:bg-white dark:hover:bg-gray-800 text-gray-600 dark:text-gray-400 hover:text-soft-blue-600 dark:hover:text-soft-blue-400 transition-all duration-200 opacity-0 group-hover:opacity-100"
                              aria-label="Add to board"
                            >
                              <PlusIcon className="h-4 w-4" />
                            </button>

                            {/* Board Selection Dropdown */}
                            {showAddToBoard === article.id && (
                              <div className="absolute right-0 mt-2 w-48 rounded-xl shadow-lg bg-white dark:bg-gray-800 ring-1 ring-soft-blue-100 dark:ring-gray-700 overflow-hidden z-30">
                                <div className="py-2">
                                  {boards.map((board) => {
                                    const isInBoard = board.articleIds.includes(article.id)
                                    return (
                                      <button
                                        key={board.id}
                                        onClick={(e) => {
                                          e.stopPropagation()
                                          if (isInBoard) {
                                            handleRemoveFromBoard(article.id, board.id)
                                          } else {
                                            handleAddToBoard(article.id, board.id)
                                          }
                                        }}
                                        className={`w-full px-4 py-2 text-sm text-left transition-colors ${
                                          isInBoard
                                            ? 'bg-soft-blue-50 dark:bg-soft-blue-900/30 text-soft-blue-700 dark:text-soft-blue-300'
                                            : 'text-soft-blue-700 dark:text-gray-300 hover:bg-soft-blue-50 dark:hover:bg-gray-700'
                                        }`}
                                      >
                                        {isInBoard ? '✓ ' : ''}{board.name}
                                      </button>
                                    )
                                  })}
                                </div>
                              </div>
                            )}
                          </div>

                          {/* Remove Button */}
                          <button
                            onClick={(e) => {
                              e.stopPropagation()
                              handleRemoveArticle(article.id)
                            }}
                            className="p-2 rounded-full bg-white/90 dark:bg-gray-800/90 backdrop-blur-sm hover:bg-white dark:hover:bg-gray-800 text-gray-600 dark:text-gray-400 hover:text-red-600 dark:hover:text-red-400 transition-all duration-200 opacity-0 group-hover:opacity-100"
                            aria-label="Remove article"
                          >
                            <BookmarkSlashIcon className="h-4 w-4" />
                          </button>
                        </div>
                      </div>

                      {/* TEXT */}
                      <div className="p-5">
                        <h3 className="text-lg font-serif font-semibold text-soft-blue-800 dark:text-gray-100">
                          {article.headline}
                        </h3>
                        <p className="text-sm text-soft-blue-600 dark:text-gray-400 mt-2">
                          {article.subtitle}
                        </p>
                        <div className="mt-3 flex items-center justify-between">
                          <p className="text-xs text-soft-blue-500 dark:text-gray-500 flex items-center gap-1">
                            <BookmarkIcon className="h-3 w-3" />
                            {formatDate(article.savedDate)}
                          </p>
                          {articleBoards.length > 0 && (
                            <div className="flex gap-1">
                              {articleBoards.slice(0, 2).map((board) => (
                                <span
                                  key={board.id}
                                  className="text-xs px-2 py-0.5 rounded-full bg-soft-blue-100 dark:bg-soft-blue-900/30 text-soft-blue-700 dark:text-soft-blue-300"
                                >
                                  {board.name}
                                </span>
                              ))}
                              {articleBoards.length > 2 && (
                                <span className="text-xs text-soft-blue-500 dark:text-gray-500">
                                  +{articleBoards.length - 2}
                                </span>
                              )}
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  )
                })}
              </div>
            ) : (
              <div className="text-center py-16">
                <BookmarkIcon className="mx-auto h-16 w-16 text-soft-blue-300 dark:text-gray-600" />
                <h3 className="mt-6 text-2xl font-serif font-normal text-soft-blue-800 dark:text-gray-100">
                  {selectedBoard ? 'no articles in this board' : 'no clippings yet'}
                </h3>
                <p className="mt-3 text-sm text-soft-blue-600 dark:text-gray-400">
                  {selectedBoard 
                    ? 'add articles to this board to see them here.'
                    : 'start saving articles from the newsstand to see them here.'}
                </p>
              </div>
            )}
          </>
        ) : (
          <div className="text-center py-16">
            <BookmarkIcon className="mx-auto h-16 w-16 text-soft-blue-300 dark:text-gray-600" />
            <h3 className="mt-6 text-2xl font-serif font-normal text-soft-blue-800 dark:text-gray-100">
              no clippings yet
            </h3>
            <p className="mt-3 text-sm text-soft-blue-600 dark:text-gray-400">
              start saving articles from the newsstand to see them here.
            </p>
          </div>
        )}
      </div>
    </div>
  )
}
